def is_paramtools_format(params: Union[TaxcalcReform, ParamToolsAdjustment]):
    """
    Check first item in ``params`` to determine if it is using the ParamTools
    adjustment or the Tax-Calculator reform format.
    If first item is a ``dict``, then it is likely be a Tax-Calculator reform.
    Otherwise, it is likely to be a ParamTools format.

    Parameters
    ----------
    params: dict
        Either a ParamTools or Tax-Calculator styled parameters ``dict``.

        .. code-block:: python

            # ParamTools style format:
            {
                "ss_rate": {2024: 0.2}
            }

            # Tax-Calculator style format:
            {
                "ss_rate": [{"year": 2024, "value": 0.2}]}
            }

# Tax-Calculator style format:
            {
                "ss_rate": [{"year": 2024, "value": 0.2}]}
            }

    Returns:
    -------
    bool:
      Whether ``params`` is likely to be a ParamTools formatted
      adjustment or not.
    """
    for data in params.values():
        if isinstance(data, dict):
            return False  # taxcalc reform
        # Not doing a specific check to see if the value is a list
        # since it could be a list or just a scalar value.
        return True

def has_response(self):
        """
        Return true if any MPC parameters are positive for current_year or
        if any BEN value parameters are less than one for current_year;
        return false if all MPC parameters are zero and all BEN value
        parameters are one
        """
        for var in Consumption.RESPONSE_VARS:
            if getattr(self, f'MPC_{var}') > 0.0:
                return True
        for var in Consumption.BENEFIT_VARS:
            if getattr(self, f'BEN_{var}_value') < 1.0:
                return True
        return False

    def response(self, records, income_change):
        """
        Changes consumption-related records variables given income_change
        and the current values of the MPC consumption parameters
        """
        if not isinstance(records, Records):
            raise ValueError('records is not a Records object')
        for var in Consumption.RESPONSE_VARS:
            records_var = getattr(records, var)
            mpc_var = getattr(self, f'MPC_{var}')
            records_var[:] += mpc_var * income_change

